-- PostgreSQL compatibility for QCS product unqualified-deal pages.
--
-- QCSUnQlfDealController.data/editStates calls QCSUnQlfDealDao.findSupervision,
-- which maps QCSUnQlfDealSupervision to QCS_UN_QLF_DEALS_SV. The recovered
-- PostgreSQL object can exist with only table_info_id/staff, while Hibernate
-- selects inherited id/version/main_obj/valid columns. Expose those fields from
-- qcs_un_qlf_deals so the generated edit/view pages can load.

DO $$
BEGIN
  IF to_regclass('public.qcs_un_qlf_deals') IS NOT NULL
     AND (to_regclass('public.qcs_un_qlf_deals_sv') IS NULL OR EXISTS (
       SELECT 1
       FROM pg_class c
       JOIN pg_namespace n ON n.oid = c.relnamespace
       WHERE n.nspname = 'public'
         AND c.relname = 'qcs_un_qlf_deals_sv'
         AND c.relkind = 'v'
     )) THEN
    EXECUTE $view$
CREATE OR REPLACE VIEW public.qcs_un_qlf_deals_sv AS
SELECT
  table_info_id,
  owner_staff_id AS staff,
  id,
  version,
  true::boolean AS valid,
  id AS main_obj,
  create_staff_id,
  modify_staff_id,
  delete_staff_id,
  create_time,
  modify_time,
  delete_time
FROM public.qcs_un_qlf_deals
WHERE table_info_id IS NOT NULL
  AND owner_staff_id IS NOT NULL
$view$;
  END IF;
END $$;

